-- Generated by bqetl generate firefox_crashes
{% for table_name, fields in tables.items() %}
  SELECT
    {{ fields }},
    COALESCE(metrics.string.crash_app_build, client_info.app_build) AS crash_app_build,
    COALESCE(metrics.string.crash_app_channel, client_info.app_channel) AS crash_app_channel,
    COALESCE(metrics.string.crash_app_display_version, client_info.app_display_version) AS crash_app_display_version,
  FROM
   `{{ table_name }}`
  WHERE
    DATE(submission_timestamp) = @submission_date
  -- dedupe based on minidump hash but keep all null and empty minidumps
  QUALIFY
    metrics.string.crash_minidump_sha256_hash = 'e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855'
    OR metrics.string.crash_minidump_sha256_hash IS NULL
    OR ROW_NUMBER() OVER(
      PARTITION BY DATE(submission_timestamp), metrics.string.crash_minidump_sha256_hash
      ORDER BY submission_timestamp
    ) = 1
  {% if not loop.last %}
    UNION ALL
  {% endif %}
{% endfor %}
